#include <fcntl.h>
#include <unistd.h>
#include <stdio.h>

struct flock lockFile(int fd, int type) {
    struct flock lock;
    lock.l_type = type;    // F_RDLCK (shared), F_WRLCK (exclusive), F_UNLCK (unlock)
    lock.l_whence = SEEK_SET;
    lock.l_start = 0;
    lock.l_len = 0;  // Lock entire file
    lock.l_pid = getpid();

    if (fcntl(fd, F_SETLKW, &lock) == -1) {
        perror("Lock failed");
    }
    return lock;
}

int main() {
    int fd = open("shared.txt", O_RDWR | O_CREAT, 0644);

    // Acquire exclusive (write) lock
    struct flock lock = lockFile(fd, F_WRLCK);

    // Critical section: write to file
    write(fd, "Data from process", 17);

    // Release lock
    lock.l_type = F_UNLCK;
    fcntl(fd, F_SETLK, &lock);

    close(fd);
    return 0;
}

import java.io.RandomAccessFile;
import java.nio.channels.FileChannel;
import java.nio.channels.FileLock;
import java.io.IOException;

public class SharedFileAccess {
    private RandomAccessFile file;
    private FileChannel channel;
    private FileLock lock;

    public boolean lockFile(boolean shared) throws IOException {
        // Open file in read-write mode
        file = new RandomAccessFile("shared.txt", "rw");
        channel = file.getChannel();

        // Try to acquire lock (non-blocking)
        lock = channel.tryLock(0, Long.MAX_VALUE, shared);

        if (lock == null) {
            System.out.println("Could not acquire lock - file is locked");
            return false;
        }

        System.out.println(shared ? "Shared lock acquired" : "Exclusive lock acquired");
        return true;
    }

    public void writeToFile(String data) throws IOException {
        if (lock == null || !lock.isValid()) {
            throw new IOException("No valid lock held");
        }

        file.writeBytes(data);
        System.out.println("Written: " + data);
    }

    public String readFromFile() throws IOException {
        if (lock == null || !lock.isValid()) {
            throw new IOException("No valid lock held");
        }

        // Reset to beginning
        file.seek(0);

        byte[] data = new byte[(int) file.length()];
        file.readFully(data);
        return new String(data);
    }

    public void unlockFile() throws IOException {
        if (lock != null && lock.isValid()) {
            lock.release();
            System.out.println("Lock released");
        }
        if (channel != null) channel.close();
        if (file != null) file.close();
    }

    public static void main(String[] args) {
        try {
            SharedFileAccess access = new SharedFileAccess();

            // Acquire exclusive lock
            if (access.lockFile(false)) {
                access.writeToFile("Hello from Java!");
                access.unlockFile();
            }

            // Acquire shared lock (for reading)
            if (access.lockFile(true)) {
                String content = access.readFromFile();
                System.out.println("Read: " + content);
                access.unlockFile();
            }

        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}
